thisDir = fileparts(mfilename('fullpath'));
figDir = fullfile(thisDir, 'figures');

%% Loaded results
load(fullfile(thisDir,'mlp_results.mat'),'mlp_results');
load(fullfile(thisDir,'cnn_results.mat'),'cnn_results');
