disp(t);

%% MLP - 5 runs per structure (Tables 2-3)
files = dir(fullfile(thisDir,'table2_3_mlp_runs_*.csv'));
for i = 1:numel(files)
    fprintf('\\n-- %s --\\n', files(i).name);
    t = readtable(fullfile(thisDir, files(i).name));
    disp(t);
end

%% MLP - Summary (Table 4)
t = readtable(fullfile(thisDir,'table4_mlp_summary.csv'));
disp(t);

%% CNN - Hyperparameters (Table 5)
t = readtable(fullfile(thisDir,'table5_cnn_models_hyperparams.csv'));
disp(t);

%% CNN - 5 runs per architecture (Tables 6-8)
files = dir(fullfile(thisDir,'table6_8_cnn_runs_*.csv'));
for i = 1:numel(files)
    fprintf('\\n-- %s --\\n', files(i).name);
    t = readtable(fullfile(thisDir, files(i).name));
    disp(t);
end

%% CNN - Summary (Table 9)
t = readtable(fullfile(thisDir,'table9_cnn_summary.csv'));
disp(t);

%% Dropout analysis (Tables 10-11)
t10 = readtable(fullfile(thisDir,'table10_dropout_overfit.csv'));
