%% Figures
if exist(figDir,'dir')
    imgs = dir(fullfile(figDir,'*.png'));
    for i = 1:numel(imgs)
        p = fullfile(figDir, imgs(i).name);
        try
            I = imread(p);
            figure('Name', imgs(i).name);
            image(I);
            axis image off;
            title(strrep(imgs(i).name,'_','\\_'));
        catch ME
            fprintf('Could not render %s: %s\\n', imgs(i).name, ME.message);
        end
    end
else
    disp('No figures folder found.');
end
